  requires "default" in rules
  requires "queue" in rules["default"]
  requires "priority" in rules["default"]
  ensures |result| <= |tickets|
{
  result := [];
  var i := 0;
  while i < |tickets|
    invariant 0 <= i <= |tickets|
    invariant |result| <= i
  {
    var ticket := tickets[i];
    if "id" in ticket && "severity" in ticket && "service" in ticket {
      var tid := ticket["id"];
      var severity := ticket["severity"];
      var service := ticket["service"];

      var rule_dict: map<string, string>;
      if service in rules {
        rule_dict := rules[service];
      } else {
        rule_dict := rules["default"];
      }

      if "queue" in rule_dict && "priority" in rule_dict {
        var queue := rule_dict["queue"];
        var base_priority_str := rule_dict["priority"];

        // Parse base priority as integer
        var base_priority := parse_int(base_priority_str);

        var extra := 0;
        if severity == "critical" {
          extra := 10;
        } else if severity == "high" {
          extra := 5;
        }

        var final_priority := base_priority + extra;
        var priority_str := int_to_string(final_priority);

        var row := map["id" := tid, "queue" := queue, "priority" := priority_str, "status_code" := "routed"];
        result := result + [row];
      }
    }
    i := i + 1;
  }
}

